use std::collections::HashMap;

struct ArticleMetadata {
    id: u64,
    title_len: usize,
    content_start: u64,
}

fn process_article_data(records: Vec<ArticleMetadata>) -> HashMap<u64, String> {
    let mut cache = HashMap::new();
    for record in records.into_iter() {
        let key = record.id;
        let title = format!("Title for ID {}", key);
        let content = "This is the optimized content block.".to_string();
        cache.insert(key, title + &content);
