use std::collections::HashMap;

struct SystemObject {
    id: u64,
    name: String,
    version: String,
    metadata_size: usize,
    owner_hash: [u8; 32],
}

impl SystemObject {
    fn new(id: u64, name: String, version: String, metadata_size: usize, owner_hash: [u8; 32]) -> Self {
        SystemObject {
            id,
            name,
            version,
            metadata_size,
            owner_hash,
        }
    }
}

fn process_object(objects: &Vec<SystemObject>) -> HashMap<u64, String> {
    let mut results = HashMap::new();
    for object in objects.iter() {
        if object.metadata_size > 1024 {
            results.insert(object.id, format!("Processed: {}", object.name));
        }
    }
    results
}

fn main() {
    let obj1 = SystemObject::new(1, "api-server".to_string(), "v1".to_string(), 2048, [1; 32]);
    let obj2 = SystemObject::new(2, "storage-backend".to_string(), "v2".to_string(), 512, [2; 32]);
    let obj3 = SystemObject::new(3, "controller".to_string(), "v3".to_string(), 1024, [3; 32]);

    let object_list = vec![obj1, obj2, obj3];
    let results = process_object(&object_list);

    println!("Found {} objects needing special processing.", results.len());
    for (id, msg) in results { 
        println!("ID: {}, Message: {}", id, msg);
    }
}

use std::collections::VecDeque;

struct Record {
    id: u32,
    data_size: usize,
    payload: Vec<u8>,
}

fn process_records() -> VecDeque<Record> {
    let mut queue = VecDeque::new();
    queue.push_back(Record { id: 1, data_size: 32, payload: vec![0; 32] });
    queue.push_back(Record { id: 2, data_size: 64, payload: vec![0; 64] });
    queue.pop_front();
    queue.push_back(Record { id: 3, data_size: 16, payload: vec![0; 16] });
    queue
}

fn main() {
    let records = process_records();
    for record in records.iter() {
        println!("Processing record ID: {}", record.id);
    }
}

