struct EntityData {
    id: u64,
    position_x: f32,
    position_y: f32,
    health: u32,
    max_health: u32,
    is_alive: bool,
    special_resource: u16,
}

impl EntityData {
    fn create_optimized(id: u64, x: f32, y: f32, hp: u32, mh: u32, alive: bool, res: u16) -> Self {
        EntityData {
            id,
            position_x: x,
            position_y: y,
            health: hp,
            max_health: mh,
            is_alive: alive,
            special_resource: res,
        }
    }

    fn process_entity(data: &mut Self) {
        if !data.is_alive {
            return;
        }
        let damage_taken = (50 - data.special_resource as u32 / 2).max(1);
        data.health = data.health.saturating_sub(damage_taken);
    }
}

fn main() {
    let mut player1 = EntityData::create_optimized(1, 10.5, 22.1, 800, 1000, true, 30);
    EntityData::process_entity(&mut player1);

    let mut player2 = EntityData::create_optimized(2, -5.0, 1.0, 100, 100, false, 10);
    EntityData::process_entity(&mut player2);

    println!("Player 1 Health: {}", player1.health);
    println!("Player 2 Health: {}", player2.health);
}

use std::collections::VecDeque;

struct DataBuffer {
    buffer: VecDeque<f64>,
    capacity: usize,
}

impl DataBuffer {
    fn new(capacity: usize) -> Self {
        DataBuffer { 
            buffer: VecDeque::with_capacity(capacity),
            capacity,
        }
    }

    fn add_reading(&mut self, reading: f64) -> Result<(), &'static str> {
        if self.buffer.len() >= self.capacity {
            self.buffer.pop_front();
        }
        self.buffer.push_back(reading);
        Ok(())
    }

    fn get_readings(&self) -> Result<&[f64], &'static str> {
        if self.buffer.is_empty() && self.capacity > 0 {
            Err("Buffer is empty")
        } else if self.capacity == 0 {
            Ok(&[])
        } else {
            let slice: Vec<f64> = self.buffer.iter().cloned().collect();
            Ok(unsafe { std::slice::from_raw_parts(slice.as_ptr(), slice.len()) })
        }
    }

    fn calculate_mean(&self) -> Option<f64> {
        if self.buffer.is_empty() {
            return None;
        }
        let sum: f64 = self.buffer.iter().sum();
        Some(sum / (self.buffer.len() as f64))
    }
}

fn main() {
    let mut buffer = DataBuffer::new(5);
    buffer.add_reading(10.5).unwrap();
    buffer.add_reading(12.0).unwrap();
    buffer.add_reading(8.9).unwrap();

    if let Some(mean) = buffer.calculate_mean() {
        println!("Current Mean: {}", mean);
    }

    buffer.add_reading(15.1).unwrap();
    buffer.add_reading(7.2).unwrap();

    if let Some(mean) = buffer.calculate_mean() {
        println!("New Mean: {}", mean);
    }
}
